import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"火遁","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/能量类/忍术/五行遁术/火遁.md","filePath":"4.资源分区/6.技艺及称号/能量类/忍术/五行遁术/火遁.md"}'),s={name:"4.资源分区/6.技艺及称号/能量类/忍术/五行遁术/火遁.md"};function o(d,b,l,i,_,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"火遁",tabindex:"-1"},[t("火遁 "),r("a",{class:"header-anchor",href:"#火遁","aria-label":'Permalink to "火遁"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),n('<h1 id="火遁-1" tabindex="-1">火遁 <a class="header-anchor" href="#火遁-1" aria-label="Permalink to &quot;火遁&quot;">​</a></h1><p>火遁</p><p>【火遁·豪火球之术】</p><p>C+1000<br> 消耗能量：6点<br> 使用动作：标准<br> 遁术性质：火<br> 持续时间：立即<br> 目标：扇形范围内所有单位<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*3米<br> 描述：查克拉聚集在喉咙后，从口中向前方喷吐巨大的火球，将敌人炸飞。</p><p>效果：进行一次忍术攻击检定，对扇形范围内的所有单位造成火焰能量伤害，这次攻击获得3DP火焰能量加值，获得基于火焰能量的1点附加成功。</p><p>【火遁·凤仙火之术】<br> C+1000<br> 消耗能量：6点<br> 使用动作：标准<br> 遁术性质：火<br> 持续时间：立即<br> 目标：敌方单体<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*3米<br> 描述：如同一碰就飞弹而出的凤仙花种子一样，从施术者口中吐出的火焰向四面八方散开去袭击敌人。而且，所有的火焰都是由查克拉控制，要悉数避开并不容易。除了极富视觉效果之外，威力也很惊人。还可以在飞舞的火焰中隐藏同样由查克拉控制的飞镖进行攻击。</p><p>效果：对目标进行一次忍术攻击检定，这次攻击只对目标造成成功数一半的火焰伤害。<br> 接着，你可以花招动作对目标进行一次投掷攻击，这次攻击具有C级措手不及、长点射与5点高速。</p><p>差价升级至B+2000【凤仙花爪红】</p><p>【火遁·凤仙花爪红】<br> B+2000<br> 消耗能量：10点<br> 使用动作：标准<br> 遁术性质：火<br> 持续时间：立即<br> 目标：敌方单体<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*3米<br> 描述：这个术是将火遁之火缠绕在众多手里剑上向对手发射。像是要包围对方一样，让对方眼前布满了火焰，可以在一瞬间遮蔽对方的视野，除了攻击力之外，同时具有强大的扰敌效果。为了不要让手里剑分散，这个术要在近距离下施展才能发挥出最大的效果。此外，手里剑上的火焰也会转移动敌人身上，让敌人受到更多的伤害。既拥有火遁的高热和杀伤力，又具备手里剑的切割能力，是手里剑加上火焰的双重忍术</p><p>效果：进行一次忍术攻击检定，这次攻击不造成伤害而是将伤害转化为等量的燃烧点数，标准豁免。<br> 之后你可以迅捷动作再对目标进行一次投掷攻击，这次攻击具有B级措手不及、连射、高速5，这次攻击造成的伤害在穿刺与火焰伤害中取优计算。</p><p>【火遁·龙火之术】<br> C+1000<br> 消耗能量：6点<br> 使用动作：标准<br> 遁术性质：火<br> 持续时间：立即<br> 目标：直线上的所有单位<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*5米<br> 描述：如同火龙喷出的火焰一样，一直线地侵袭对手。不同于豪火球会包围敌人的攻击，龙火会直线形地瞄准敌人的怀中袭击而去.</p><p>效果：进行一次忍术攻击检定，这次攻击获得6点火焰能量加值，对一条直线上所有单位造成火焰伤害，反射豁免。</p><p>差价升级B+2000</p><p>【火遁·豪龙火之术】<br> B+2000<br> 消耗能量：10<br> 使用动作：标准<br> 遁术性质：火<br> 持续时间：立即<br> 目标：直线上所有单位<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*7米<br> 描述：在体内聚集大量的查克拉并将其压缩而成的炎龙形态，巧妙地操纵炎龙来袭击眼前的敌人，熟练度高的话可以连续放出数条炎龙。比起攻击范围，豪龙火之术更重视攻击威力和准确性，被炎龙的锐牙击中的敌人，将在瞬间被烧成灰烬。</p><p>效果：进行一次忍术攻击检定，对一条直线上所有单位造成火焰伤害，这次攻击获得操控属性点火焰能量加值，受到伤害的目标以反射豁免。<br> 这次攻击可投掷二次并取较高者作为结果计算攻击成功数。</p><p>每影片结束时，如果你以此忍术击败过同等级的敌人，你可以在使用此忍术时对面前扇形区域再额外释放一条炎龙，炎龙多次命中一个单位伤害不叠加</p><p>【火遁·炎弹】<br> C+1000<br> 消耗能量：6点<br> 使用动作：标准<br> 遁术性质：火<br> 持续时间：立即<br> 目标：扇形群体<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*3米<br> 描述：自来也使用的火遁忍术，将体内仙术查克拉练成油，在充满口腔的油吐出的同时使用火遁忍术将其燃烧。</p><p>效果：进行一次忍术攻击检定，对范围内敌人造成火焰能量伤害，这次攻击附带基于火焰能量的1点附加成功，目标以强韧豁免。命中后附带10点燃烧点数，正常豁免。</p><p>差价升级至B+2000</p><p>【火遁·大炎弹】<br> B+2000<br> 消耗能量：10点<br> 使用动作：标准<br> 遁术性质：火<br> 持续时间：立即<br> 目标：射程内任意一个点<br> 忍术成分：姿势、语言、忍印<br> 射程：操控*4米<br> 描述：释放的怪异巨型炎弹，烧尽天地无处可逃</p><p>效果：进行一次忍术攻击检定，对指定位置周围操控*2米内的所有单位造成火焰能量伤害，强韧豁免。这次攻击附带5DP火焰能量加值与1点基于火焰能量加值的附加成功。<br> 你可选择这次攻击不造成伤害而是转化为等量的燃烧异常点数，标准豁免。</p><p>【火遁·灰积烧】<br> B+2000<br> 消耗能量：10点<br> 使用动作：标准<br> 遁术性质：火<br> 持续时间：立即<br> 目标：距离内指定的一个点<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*5米<br> 描述：向前方吐出一团高温的烟灰，烟灰落地后会对敌人产生高温伤害，持续一段时间后爆炸，可在嘴里藏打火石，喷吐后直接咬打火石进行引爆。</p><p>效果：进行一次忍术攻击检定，在目标地点周围操控*2米的圆形区域生成一团浓厚的易燃烟雾。处于烟雾内的单位将无法看清周围环境，这是一个B级环境来源的目盲效果，烟雾至多持续三轮。<br> 注：若场景为有风的环境，烟雾可能散去的更快，但至少会持续存在一轮。<br> 当烟雾区域内出现任何【火焰】、燃烧点数时，这一烟雾会立即被点燃爆炸，处于烟雾内的所有单位均需要进行强韧豁免，DC为你忍术检定的成功数，失败承受差额的火焰伤害。目标这次强韧豁免承受等于你操控属性的环境减值。<br> 你可以选择花费一个花招动作吐出打火石直接引燃烟雾。</p><p>【火遁·豪火灭却】<br> A+4000<br> 消耗能量：14点<br> 使用动作：标准<br> 遁术性质：火<br> 持续时间：立即<br> 目标：群体<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*20米<br> 描述：查克拉聚集在喉咙后，向前方吐出一大片如同海水一般的火焰，其势足以吞没一片森林。</p><p>效果：进行一次忍术攻击检定，对范围内所有敌人造成火焰能量伤害，这次攻击检定获得等同于人物操控属性点火焰加值，这次攻击具有【扼魂】特性，目标以反射豁免此次攻击检定的出目。<br> 受到伤害的目标在一轮内失去格挡防御，这是一个A级创伤来源的负面效果。</p><p>【火遁·豪火灭失】<br> A+4000<br> 消耗能量：14点<br> 使用动作：标准<br> 遁术性质：火<br> 持续时间：立即<br> 目标：锥形范围内所有敌人<br> 忍术成分：姿势、语言、忍印<br> 距离：操控*10米<br> 描述：火遁·豪火灭失是宇智波斑擅长使用的火遁忍术之一，将查克拉聚集在喉咙后，朝地面吐出一颗陨石降落模样的火球，落地后火焰会迅速扩散，遍布之地化为一片火海，业火之炎将敌人和大地燃烧殆尽</p><p>效果：进行一次忍术攻击检定，获得等同于人物操控属性点火焰加值，对锥形范围内所有敌人造成火焰能量伤害，反射豁免。<br> 本次攻击命中后附带等同伤害值的燃烧点数，标准豁免。<br> 这次攻击生效后，攻击覆盖的区域会在三轮内残留有极高温度的火焰，若有单位在这一区域内结束自身的回合，其需要进行一次强韧豁免，DC为此次攻击检定的成功数。失败则受到差额点火焰伤害。这是一个A级、环境来源的负面效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',29)])])}const B=p(s,[["render",o]]);export{f as __pageData,B as default};
